mapper.select:


    vc.del_flag = '0'
     and vc.street_office_id = #{streetOfficeId}
     and vc.village_code = #{villageCode}
     and vc.village_name like concat('%', #{villageName}, '%')
     and vc.status = #{status}

order by vc.sort_order asc, vc.create_time desc

select count(1) from shebao_village_committee 
where street_office_id = #{streetOfficeId} and village_code = #{villageCode} and del_flag = '0'
 and id != #{id}

select count(1) from shebao_village_committee 
where street_office_id = #{streetOfficeId} and village_name = #{villageName} and del_flag = '0'
 and id != #{id}
